package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsNullStringSet_WhenNullStringIsNull() throws Exception {
        // Create a new instance with null nullString using withNullString(null)
        csvFormat = csvFormat.withNullString(null);
        assertFalse(csvFormat.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_WhenNullStringIsNotNull() throws Exception {
        // Create a new instance with non-null nullString using withNullString("NULL")
        csvFormat = csvFormat.withNullString("NULL");
        assertTrue(csvFormat.isNullStringSet());
    }
}
